values
  ('00000000-0000-0000-0000-000000000001', 'pixelcraft-studio', 'published', 'PixelCraft Studio', 'iOS APP · BILDBEARBEITUNG', 'KI-Foto-Editor für iOS', 'Premium-Foto-Editor mit über 150.000 Downloads. KI-gestützte Filter, abgeschlossene Architektur, sauberer SwiftUI-Code. Inkl. App-Store-Account-Transfer.', 'One-Time + In-App', 'PixelCraft Studio ist ein etablierter Premium-Foto-Editor für iOS mit treuer Nutzerbasis und stabilem Umsatz. Die Architektur ist abgeschlossen, vollständig in SwiftUI gehalten und sauber modularisiert — ein neuer Eigentümer kann sofort weiterbauen. Der Verkauf umfasst Source-Code, App-Store-Account-Transfer und eine 30-tägige Übergabebegleitung.', 'P', 'icon-1', '€32.500', 'Komplettverkauf', '≈ 15× Monatsumsatz', 'ios', 'onetime', 'full', 2180, 32500, '2026-05-12', '{"tech":["Swift","SwiftUI","CoreML","CloudKit"],"metrics":[{"label":"Downloads","val":"152k"},{"label":"Monatl. Umsatz","val":"€2.180","trend":"+12%"},{"label":"Alter","val":"3,1","small":"J."}],"highlights":["150k+ Downloads, rein organisch gewachsen","Sauberer, modularer SwiftUI-Code","App-Store-Account-Transfer inklusive","KI-Filter on-device über CoreML"],"financials":[{"label":"Monatl. Umsatz","val":"€2.180","trend":"+12%"},{"label":"Downloads","val":"152k"},{"label":"Rating","val":"4,8","small":"★"},{"label":"Marge","val":"88","small":"%"},{"label":"Refund-Rate","val":"1,2","small":"%"},{"label":"Code-Audit","val":"A"}],"seller":{"name":"Marek S.","avatar":"M","rating":"★ 4.9 · 7 Verkäufe"},"badges":[{"label":"Verifiziert","kind":"verified"},{"label":"Hot","kind":"hot"}]}'::jsonb),
  ('00000000-0000-0000-0000-000000000001', 'documind-ai', 'published', 'DocuMind AI', 'SAAS · KI / DOKUMENTEN-ANALYSE', 'B2B-Vertragsanalyse mit KI', 'B2B-Plattform für automatische Vertragsanalyse. 38 Enterprise-Kunden, MRR steigt seit 14 Monaten. Verkäufer bietet 4-Wochen-Handover an.', 'SaaS · MRR', 'DocuMind AI automatisiert die Vertragsanalyse für Mittelstand und Enterprise. Die Plattform wächst seit 14 Monaten verlässlich, hat geringe Churn und einen klaren Upsell-Pfad. Der Gründer bietet eine strukturierte 4-Wochen-Übergabe inklusive Kundengespräche an.', 'D', 'icon-2', '€164.000', 'Firmen-Übernahme', '≈ 14× MRR', 'ai', 'mrr', 'full', 11400, 164000, '2026-05-20', '{"tech":["Next.js","Python","FastAPI","OpenAI","Postgres"],"metrics":[{"label":"MRR","val":"€11.400","trend":"+8%"},{"label":"Kunden","val":"38"},{"label":"Churn","val":"2,1","small":"%"}],"highlights":["38 Enterprise-Kunden, 14 Monate MRR-Wachstum","4-Wochen-Handover durch den Gründer","Anwaltlich geprüfte Verträge im Stack","DSGVO-konform, EU-Hosting"],"financials":[{"label":"MRR","val":"€11.400","trend":"+8%"},{"label":"ARR","val":"€136.800"},{"label":"Kunden","val":"38"},{"label":"Churn","val":"2,1","small":"%"},{"label":"Brutto-Marge","val":"79","small":"%"},{"label":"LTV","val":"€12.4k"}],"seller":{"name":"Aydan K.","avatar":"A","rating":"★ 5.0 · 2 Verkäufe"},"badges":[{"label":"Verifiziert","kind":"verified"}]}'::jsonb),
  ('00000000-0000-0000-0000-000000000001', 'habitcircle', 'published', 'HabitCircle', 'CROSS-PLATFORM · LIFESTYLE', 'Habit-Tracker, iOS + Android', 'Habit-Tracker mit Freemium-Modell, läuft auf iOS und Android. 24k aktive Nutzer, organisches Wachstum, kein Marketing-Budget bisher.', 'Freemium', 'HabitCircle ist ein wachsender Habit-Tracker mit treuer Community und vollständig organischem Wachstum. Eine einzige Flutter-Codebase bedient iOS und Android. Ideal für einen Käufer, der mit etwas Marketing-Budget skalieren möchte.', 'H', 'icon-3', '€9.800', 'Komplettverkauf', '≈ 13× Monatsumsatz', 'android', 'iap', 'full', 720, 9800, '2026-05-25', '{"tech":["Flutter","Firebase","RevenueCat"],"metrics":[{"label":"Aktive User","val":"24k"},{"label":"Monatl. Umsatz","val":"€720"},{"label":"Alter","val":"1,2","small":"J."}],"highlights":["24k aktive Nutzer, 0 € Marketing-Budget","iOS + Android aus einer Flutter-Codebase","RevenueCat-Abrechnung integriert","Hohes organisches Wachstum"],"financials":[{"label":"Aktive User","val":"24k"},{"label":"Monatl. Umsatz","val":"€720"},{"label":"Plattform","val":"iOS+Android"},{"label":"Conversion","val":"3,1","small":"%"},{"label":"Alter","val":"1,2","small":"J."},{"label":"Marge","val":"92","small":"%"}],"seller":{"name":"Lena M.","avatar":"L","rating":"★ 4.7 · 1 Verkauf"},"badges":[{"label":"Neu","kind":"new"}]}'::jsonb),
  ('00000000-0000-0000-0000-000000000001', 'vendorvault', 'published', 'VendorVault', 'SAAS · B2B INVENTARVERWALTUNG', 'Lager-Software für Mittelstand', 'Etablierte Lager-Software für Mittelstand. Verkäufer sucht Co-Founder/Investor — bietet 35% Anteile für €67k. Vollständige Übergabe der Tech-Verantwortung möglich.', 'SaaS · Anteilsverkauf', 'VendorVault ist eine etablierte Inventar- und Lagerlösung für den Mittelstand. Der Gründer sucht keinen reinen Exit, sondern einen technischen Co-Founder oder Investor und bietet 35 % Anteile. Die technische Verantwortung kann vollständig übergeben werden.', 'V', 'icon-4', '€67.000', 'Für 35% Anteile', 'Bewertung ≈ €191k', 'saas', 'mrr', 'shares', 4890, 67000, '2026-05-18', '{"tech":["Ruby on Rails","React","Postgres","Redis"],"metrics":[{"label":"MRR","val":"€4.890"},{"label":"Kunden","val":"61"},{"label":"Anteile","val":"35","small":"%"}],"highlights":["35 % Anteile + technische Verantwortung","61 Mittelstands-Kunden, stabile Basis","Gründer sucht Co-Founder / Investor","Rails + React, gut dokumentiert"],"financials":[{"label":"MRR","val":"€4.890"},{"label":"ARR","val":"€58.680"},{"label":"Kunden","val":"61"},{"label":"Anteile","val":"35","small":"%"},{"label":"Bewertung","val":"€191k"},{"label":"Churn","val":"1,8","small":"%"}],"seller":{"name":"Thomas R.","avatar":"T","rating":"★ 4.8 · 3 Deals"},"badges":[{"label":"Verifiziert","kind":"verified"},{"label":"Anteile","kind":"plain"}]}'::jsonb),
  ('00000000-0000-0000-0000-000000000001', 'codereview-bot', 'published', 'CodeReview Bot', 'DEV-TOOL · GITHUB-INTEGRATION', 'Automatisierte Code-Reviews', 'GitHub-App für automatisierte Code-Reviews mit GPT-Backend. 320 zahlende Teams, vollständige Dokumentation, sauberer Test-Coverage.', 'SaaS · MRR', 'CodeReview Bot bringt automatisierte, GPT-gestützte Code-Reviews direkt in den GitHub-Workflow. 320 zahlende Teams, schlanke Infrastruktur und ein aktives Marketplace-Listing sorgen für planbare, margenstarke Umsätze.', 'C', 'icon-5', '€18.400', 'Komplettverkauf', '≈ 11× MRR', 'devtool', 'mrr', 'full', 1620, 18400, '2026-05-08', '{"tech":["Node.js","TypeScript","GitHub API","OpenAI"],"metrics":[{"label":"Teams","val":"320"},{"label":"MRR","val":"€1.620","trend":"+4%"},{"label":"Margin","val":"71","small":"%"}],"highlights":["320 zahlende Teams","Vollständige Tests & Dokumentation","GitHub-Marketplace-Listing aktiv","GPT-Backend, schlanke Infrastruktur"],"financials":[{"label":"MRR","val":"€1.620","trend":"+4%"},{"label":"ARR","val":"€19.440"},{"label":"Teams","val":"320"},{"label":"Marge","val":"71","small":"%"},{"label":"Churn","val":"3,4","small":"%"},{"label":"Alter","val":"2,0","small":"J."}],"seller":{"name":"Niko F.","avatar":"N","rating":"★ 4.9 · 5 Verkäufe"},"badges":[{"label":"Verifiziert","kind":"verified"}]}'::jsonb),
  ('00000000-0000-0000-0000-000000000001', 'rhythmica', 'published', 'Rhythmica', 'iOS APP · MUSIK / SPIEL', 'Indie-Rhythm-Spiel', 'Indie-Rhythm-Spiel mit eigener Engine. 89k Downloads, Featured-Spot im App-Store, starkes Review-Profil. Source-Code in Swift mit Metal.', 'In-App Käufe', 'Rhythmica ist ein handgemachtes Indie-Rhythm-Spiel mit eigener Metal-Engine und einem App-Store-Featured-Spot in der Historie. Das starke Review-Profil und die treue Spielerbasis machen es zu einer attraktiven Übernahme für Studios oder Solo-Entwickler.', 'R', 'icon-6', '€24.000', 'Komplettverkauf', '≈ 17× Monatsumsatz', 'game', 'iap', 'full', 1420, 24000, '2026-05-15', '{"tech":["Swift","Metal","AudioKit"],"metrics":[{"label":"Downloads","val":"89k"},{"label":"In-App / Monat","val":"€1.420"},{"label":"Rating","val":"4,8","small":"★"}],"highlights":["89k Downloads, App-Store-Featured","Eigene Metal-Rendering-Engine","Starkes Review-Profil (4,8 ★)","Source in Swift + AudioKit"],"financials":[{"label":"Downloads","val":"89k"},{"label":"In-App / Monat","val":"€1.420"},{"label":"Rating","val":"4,8","small":"★"},{"label":"Marge","val":"90","small":"%"},{"label":"Featured","val":"✓"},{"label":"Engine","val":"Eigen"}],"seller":{"name":"Sasha B.","avatar":"S","rating":"★ 4.6 · 2 Verkäufe"},"badges":[{"label":"Hot","kind":"hot"}]}'::jsonb),
  ('00000000-0000-0000-0000-000000000001', 'lumen-analytics', 'published', 'Lumen Analytics GmbH', 'GMBH-BETEILIGUNG · WEB-ANALYTICS', 'Profitable Analytics-SaaS als GmbH', 'Etablierte, profitable Web-Analytics-SaaS als GmbH. Die Gesellschafterin bietet 20% Anteile für €240k zur Wachstumsfinanzierung. Notarielle Anteilsübertragung, sauberer Cap-Table.', 'GmbH · Anteilsverkauf', 'Lumen Analytics GmbH betreibt eine datenschutzfreundliche Web-Analytics-Plattform mit treuer B2B-Kundschaft und planbar wiederkehrenden Umsätzen. Statt eines Exits sucht die Gründerin eine strategische Beteiligung: 20% der Gesellschaftsanteile werden notariell übertragen, das Kapital fließt in Vertrieb und Teamaufbau. Geprüfte Jahresabschlüsse und ein sauberer Cap-Table liegen für die Due Diligence bereit.', 'L', 'icon-2', '€240.000', 'Für 20% Anteile', 'Pre-Money ≈ €1,2 Mio.', 'web', 'mrr', 'shares', 21500, 240000, '2026-05-30', '{"tech":["Vue","Nuxt","ClickHouse","Go"],"metrics":[{"label":"MRR","val":"€21.500","trend":"+6%"},{"label":"Anteil","val":"20","small":"%"},{"label":"Bewertung","val":"€1,2M"}],"highlights":["20% GmbH-Anteile, notariell übertragen","Profitabel: €258k ARR, < 2% Churn","Sauberer Cap-Table, eine Gesellschafterin","Wachstumskapital für Vertrieb & Team"],"financials":[{"label":"MRR","val":"€21.500","trend":"+6%"},{"label":"ARR","val":"€258.000"},{"label":"Anteil","val":"20","small":"%"},{"label":"Pre-Money","val":"€1,2M"},{"label":"Churn","val":"1,6","small":"%"},{"label":"EBITDA-Marge","val":"34","small":"%"}],"seller":{"name":"Katrin V.","avatar":"K","rating":"★ 5.0 · 4 Deals"},"badges":[{"label":"Verifiziert","kind":"verified"},{"label":"Invest","kind":"plain"}],"equity":{"percent":20,"valuation":"€1,2 Mio."}}'::jsonb)
